using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpHttpServer;

public class WeatherTools
{
    [McpServerTool(Name = "get_weather"), Description("Gets the current weather for a city.")]
    public static string GetWeather(string city)
    {
        // Stub implementation — replace with a real API call.
        return $"The weather in {city} is 72°F and sunny.";
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpHttpServer;

[McpServerResourceType]
public class ConfigResources
{
    private static readonly Dictionary<string, object> AppSettings = new()
    {
        ["appName"] = "McpHttpServer",
        ["version"] = "1.0.0",
        ["maxRetries"] = 3,
        ["featureFlags"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["betaFeatures"] = false,
        },
    };

    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "AppSettings",
        MimeType = "application/json")]
    [Description("Returns the full application configuration as JSON.")]
    public static string GetAppSettings()
    {
        return JsonSerializer.Serialize(AppSettings, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(
        UriTemplate = "config://app/settings/{key}",
        Name = "AppSettingByKey",
        MimeType = "application/json")]
    [Description("Returns a single configuration value by key.")]
    public static string GetSettingByKey(string key)
    {
        if (AppSettings.TryGetValue(key, out var value))
        {
            return JsonSerializer.Serialize(value);
        }

        return JsonSerializer.Serialize(new { error = $"Setting '{key}' not found." });
    }
}

